from matplotlib import pyplot as pltimport cv2from skimage import io, img_as_floatfrom skimage.filters import medianimg = cv2.imread("../data/BSE_salt_pepper.jpg", 0)median_using_cv2  =cv2.medianBlur(img, 3)from skimage.morphology import diskmedian_using_skimage = median(img, disk(3), mode = 'constant', cval = 0.0)plt.figure()plt.subplot(1,2,1)plt.imshow(median_using_cv2, cmap = "gray")plt.title("median cv2")plt.subplot(1,2,2)plt.imshow(median_using_skimage, cmap = "gray")plt.title("median skimage")